<?php
declare(strict_types=1);require_once __DIR__.'/../../config/config.php';require_once ROOT_PATH.'/functions/approval_functions.php';requireAuth();if(!in_array(currentUser()['role']??'',['admin','fleet_manager'],true)){setFlash('danger','You do not have permission to approve users.');redirect('dashboard.php');}if($_SERVER['REQUEST_METHOD']==='POST'){try{if(!verifyCsrfToken((string)($_POST['csrf_token']??'')))throw new RuntimeException('Your form session expired.');decideUserApproval((int)$_POST['id'],(string)$_POST['decision'],trim((string)($_POST['reason']??'')));setFlash('success','Registration request processed.');}catch(Throwable $e){setFlash('danger',$e->getMessage());}redirect('modules/users/approvals.php');}$filter=(string)($_GET['status']??'Pending');$allowed=['Pending','Approved','Rejected'];if(!in_array($filter,$allowed,true))$filter='Pending';$stmt=getDb()->prepare('SELECT id,full_name,email,phone,role,created_at,approval_status FROM users WHERE approval_status=? ORDER BY created_at DESC');$stmt->execute([$filter]);$users=array_filter($stmt->fetchAll(),fn($u)=>approvalAccess($u));$pageTitle='User approval';require ROOT_PATH.'/includes/header.php';require ROOT_PATH.'/includes/sidebar.php';
?><main class="main-content"><?php require ROOT_PATH.'/includes/navbar.php';?><section class="page-section d-flex justify-between align-center"><div><h1 class="page-title">User approval</h1><p class="page-subtitle">Review access requests and keep operational access controlled.</p></div><div class="form-actions"><?php foreach($allowed as $status):?><a class="btn btn-secondary" href="?status=<?=e($status)?>"><?=e($status)?></a><?php endforeach;?></div></section><section class="card table-card"><div class="table-responsive"><table><thead><tr><th>Name</th><th>Email</th><th>Phone</th><th>Requested role</th><th>Registered</th><th>Status</th><th>Actions</th></tr></thead><tbody><?php foreach($users as $user):?><tr><td><?=e($user['full_name'])?></td><td><?=e($user['email'])?></td><td><?=e($user['phone'])?></td><td><?=e(ucwords(str_replace('_',' ',$user['role'])))?></td><td><?=e(formatDate($user['created_at']))?></td><td><span class="badge badge-info"><?=e($user['approval_status'])?></span></td><td><?php if($user['approval_status']==='Pending'):?><form method="post" style="display:inline"><input type="hidden" name="csrf_token" value="<?=e(csrfToken())?>"><input type="hidden" name="id" value="<?=$user['id']?>"><input type="hidden" name="decision" value="Approved"><button class="btn btn-sm btn-primary">Approve</button></form><form method="post" style="display:inline"><input type="hidden" name="csrf_token" value="<?=e(csrfToken())?>"><input type="hidden" name="id" value="<?=$user['id']?>"><input type="hidden" name="decision" value="Rejected"><input name="reason" placeholder="Reason" required><button class="btn btn-sm btn-danger">Reject</button></form><?php endif;?></td></tr><?php endforeach;?><?php if(!$users):?><tr><td colspan="7" class="empty-state">No <?=e(strtolower($filter))?> access requests.</td></tr><?php endif;?></tbody></table></div></section></main><?php require ROOT_PATH.'/includes/footer.php';?>
